// Script Continued Below
var CounterReset = Class.create();
CounterReset.prototype = {
    initialize: function() {
    },

	ResetCounter: function(dispName, scope, to_number){
		var counter = new GlideRecord('sys_number_counter');
		counter.addQuery('table.sys_name', dispName);
		counter.addQuery('table.sys_scope.scope', scope);
		counter.query();
		if(counter.next() ){
			counter.setWorkflow(false);
			counter.setValue('number', to_number);
			counter.update();
		}
	},

    type: 'CounterReset'
};
